%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n\n\n/* === TB BODY WRAPPER RESET (must be last — specificity 0,4,0 beats all :has() rules at 0,3,0) === */\n.et-l--body .et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et-l--body .et_pb_row[class*="tb_body"]{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et-l--body .et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Footer"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{padding:0 !important;margin:0 !important;background:#000864 !important;width:100% !important;max-width:100% !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Footer Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Footer Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{padding:0 !important;}"}}}} -->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<style>\\n/* ===== FOOTER — scoped for Divi specificity ===== */\\nfooter.dw-footer{background:#000864;color:#ffffff;padding:80px 0 0 0;position:relative;overflow:hidden;font-size:16px;line-height:1.5;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\\nfooter.dw-footer *{box-sizing:border-box}\\nfooter.dw-footer p,footer.dw-footer ul,footer.dw-footer li,footer.dw-footer div,footer.dw-footer span,footer.dw-footer strong{font-family:\'Noto Sans\', sans-serif;color:rgba(255,255,255,0.85)}\\nfooter.dw-footer a{font-family:\'Noto Sans\', sans-serif;color:rgba(255,255,255,0.85)}\\n\\n/* Ocean background — real PNG from brand kit */\\nfooter.dw-footer .dw-footer-ocean{position:absolute;inset:0;background:url(\\"data:image/png;base64,\\") no-repeat center bottom;background-size:100% auto;pointer-events:none;z-index:0}\\n\\nfooter.dw-footer .dw-footer-inner{max-width:1200px;margin:0 auto;padding:0 40px;position:relative;z-index:1}\\n\\nfooter.dw-footer .dw-footer-grid{display:grid;grid-template-columns:1.5fr 1fr 1fr 1fr;gap:48px;padding-bottom:60px;border-bottom:1px solid rgba(255,255,255,0.1)}\\n\\nfooter.dw-footer .dw-footer-brand{padding-right:40px;grid-column:auto}\\n\\nfooter.dw-footer .dw-footer-logo{margin-bottom:16px}\\nfooter.dw-footer .dw-footer-logo img{display:block}\\n\\nfooter.dw-footer .dw-footer-tagline{font-size:16px;color:rgba(255,255,255,0.85);line-height:1.6;margin:0 0 24px 0;padding:0}\\n\\nfooter.dw-footer .dw-footer-stock{font-size:13px;color:rgba(255,255,255,0.85);text-transform:uppercase;letter-spacing:0.05em;margin:0;padding:0}\\nfooter.dw-footer .dw-footer-stock strong{color:#00AFF0}\\n\\nfooter.dw-footer .dw-footer-heading{font-size:14px;font-weight:600;color:#ffffff;text-transform:uppercase;letter-spacing:0.05em;margin:0 0 20px 0;padding:0;line-height:1.4}\\n\\nfooter.dw-footer .dw-footer-links{list-style:none;padding:0;margin:0}\\nfooter.dw-footer .dw-footer-links li{list-style:none;margin:0 0 12px 0;padding:0;line-height:1.4}\\nfooter.dw-footer .dw-footer-links li::before{display:none;content:none}\\nfooter.dw-footer .dw-footer-links li::marker{content:none;display:none}\\nfooter.dw-footer .dw-footer-links a{font-size:15px;color:rgba(255,255,255,0.85);text-decoration:none;transition:color 0.2s ease;display:inline-flex;align-items:center;min-height:44px}\\nfooter.dw-footer .dw-footer-links a:hover{color:#00AFF0}\\n\\nfooter.dw-footer .dw-footer-contact p{font-size:15px;color:rgba(255,255,255,0.85);line-height:1.6;margin:0 0 16px 0;padding:0}\\nfooter.dw-footer .dw-footer-contact a{color:#00AFF0;text-decoration:none;display:inline-flex;align-items:center;min-height:44px}\\n\\nfooter.dw-footer .dw-footer-social{display:flex;gap:12px;margin-top:24px}\\nfooter.dw-footer .dw-footer-social a{width:48px;height:48px;background:rgba(255,255,255,0.1);border-radius:8px;display:flex;align-items:center;justify-content:center;color:#ffffff;text-decoration:none;transition:all 0.2s ease;font-weight:600}\\nfooter.dw-footer .dw-footer-social a:hover{background:#00AFF0}\\n\\nfooter.dw-footer .dw-footer-bottom{padding:24px 0;display:flex;justify-content:space-between;align-items:center}\\nfooter.dw-footer .dw-footer-copyright{font-size:14px;color:rgba(255,255,255,0.85);margin:0;padding:0}\\nfooter.dw-footer .dw-footer-legal{display:flex;gap:24px}\\nfooter.dw-footer .dw-footer-legal a{font-size:14px;color:rgba(255,255,255,0.85);text-decoration:none;transition:color 0.2s ease;padding:15px 0}\\nfooter.dw-footer .dw-footer-legal a:hover{color:#00AFF0}\\n\\n/* ===== RESPONSIVE ===== */\\n@media(max-width:1024px){\\n  footer.dw-footer .dw-footer-grid{grid-template-columns:1fr 1fr}\\n  footer.dw-footer .dw-footer-brand{grid-column:1 / -1;padding-right:0}\\n}\\n@media(max-width:640px){\\n  footer.dw-footer{padding:60px 0 0 0}\\n  footer.dw-footer .dw-footer-inner{padding:0 24px}\\n  footer.dw-footer .dw-footer-grid{grid-template-columns:1fr;gap:36px}\\n  footer.dw-footer .dw-footer-bottom{flex-direction:column;text-align:center;gap:16px}\\n  footer.dw-footer .dw-footer-legal{flex-wrap:wrap;justify-content:center}\\n}\\n\\n/* ===== REDUCED MOTION ===== */\\n@media(prefers-reduced-motion:reduce){\\n  footer.dw-footer .dw-footer-social a{transition:none}\\n  footer.dw-footer .dw-footer-links a{transition:none}\\n  footer.dw-footer .dw-footer-legal a{transition:none}\\n}</style>\\n<footer class=\\"dw-footer\\">\\n  <div class=\\"dw-footer-ocean\\" aria-hidden=\\"true\\"></div>\\n  <div class=\\"dw-footer-inner\\">\\n    <div class=\\"dw-footer-grid\\">\\n      <div class=\\"dw-footer-brand\\">\\n        <div class=\\"dw-footer-logo\\">\\n          <img src=\\"data:image/svg+xml;base64,\\" alt=\\"DigiWin\\" width=\\"140\\" height=\\"35\\">\\n        </div>\\n        <p class=\\"dw-footer-tagline\\"><span class=\\"dw-years\\">44</span> years of manufacturing intelligence. Helping factories see clearly, act decisively, and grow confidently.</p>\\n        <p class=\\"dw-footer-stock\\">Shenzhen Stock Exchange: <strong>300378</strong></p>\\n      </div>\\n\\n      <div class=\\"dw-footer-column\\">\\n        <p class=\\"dw-footer-heading\\">Products</p>\\n        <ul class=\\"dw-footer-links\\">\\n          <li><a href=\\"/products/\\">All Products</a></li>\\n          <li><a href=\\"/products/erp/\\">ERP: T100 &amp; iGP</a></li>\\n          <li><a href=\\"/products/mes/\\">MES &amp; SFT</a></li>\\n          <li><a href=\\"/products/wms/\\">WMS: sFLS</a></li>\\n          <li><a href=\\"/products/aiot/\\">AIoT &amp; Smart Factory</a></li>\\n        </ul>\\n      </div>\\n\\n      <div class=\\"dw-footer-column\\">\\n        <p class=\\"dw-footer-heading\\">Industries</p>\\n        <ul class=\\"dw-footer-links\\">\\n          <li><a href=\\"/industries/\\">All Industries</a></li>\\n          <li><a href=\\"/industries/automotive/\\">Automotive Parts</a></li>\\n          <li><a href=\\"/industries/electronics/\\">Electronics Assembly</a></li>\\n          <li><a href=\\"/industries/metal-plastics/\\">Metal &amp; Plastics</a></li>\\n        </ul>\\n        <p class=\\"dw-footer-heading\\" style=\\"margin-top:24px\\">Partners</p>\\n        <ul class=\\"dw-footer-links\\">\\n          <li><a href=\\"/partner-program/\\">Partner Program</a></li>\\n          <li><a href=\\"/partner-program/economics/\\">Partner Economics</a></li>\\n        </ul>\\n        <p class=\\"dw-footer-heading\\" style=\\"margin-top:24px\\">Resources</p>\\n        <ul class=\\"dw-footer-links\\">\\n          <li><a href=\\"/case-studies/\\">Case Studies</a></li>\\n          <li><a href=\\"/news/\\">News &amp; Events</a></li>\\n          <li><a href=\\"/blog/\\">Insights &amp; Knowledge</a></li>\\n        </ul>\\n      </div>\\n\\n      <div class=\\"dw-footer-column\\">\\n        <p class=\\"dw-footer-heading\\">Contact</p>\\n        <div class=\\"dw-footer-contact\\">\\n          <p><strong>DigiWin Thailand</strong><br>No. 2/117-118, Bangna Complex Office Tower,<br>22nd Floor, Theparat Road,<br>Bangna, Bangkok 10260</p>\\n          <p><a href=\\"mailto:info@digiwin.co.th\\">info@digiwin.co.th</a></p>\\n        </div>\\n        <div class=\\"dw-footer-social\\">\\n          <a href=\\"#\\" title=\\"LinkedIn\\">in</a>\\n          <a href=\\"#\\" title=\\"Facebook\\">f</a>\\n          <a href=\\"#\\" title=\\"LINE\\">L</a>\\n        </div>\\n      </div>\\n    </div>\\n\\n    <div class=\\"dw-footer-bottom\\">\\n      <p class=\\"dw-footer-copyright\\">&copy; <span class=\\"dw-footer-year\\">2026</span> DigiWin Thailand. All rights reserved.</p>\\n      <div class=\\"dw-footer-legal\\">\\n        <a href=\\"/privacy-policy/\\">Privacy Policy</a>\\n        <a href=\\"/terms/\\">Terms of Service</a>\\n        <a href=\\"/about-us/\\">About Us</a>\\n      </div>\\n    </div>\\n  </div>\\n</footer>\\n<script>\\n(function(){\\n  var y=new Date().getFullYear();\\n  var ys=document.querySelector(\'.dw-years\');if(ys)ys.textContent=y-1982;\\n  var yc=document.querySelector(\'.dw-footer-year\');if(yc)yc.textContent=y;\\n  /* Super D favicon */\\n  var ico=document.querySelector(\'link[rel=\\"icon\\"]\');\\n  var svg=\'data:image/svg+xml,%3Csvg xmlns=%27http://www.w3.org/2000/svg%27 viewBox=%270 0 16.73 16.89%27%3E%3Cpath fill=%27%2300AFF0%27 d=%27M0 16.89C0 15.21 1.36 13.85 3.04 13.85h5.24c2.98 0 5.41-2.42 5.41-5.41 0-2.99-2.42-5.41-5.41-5.41H3.04C1.36 3.04 0 1.68 0 0h8.28c4.66 0 8.44 3.78 8.44 8.44s-3.78 8.45-8.44 8.45z%27/%3E%3Cpath fill=%27%2300AFF0%27 d=%27M.89 8.45a2.18 2.18 0 114.36 0 2.18 2.18 0 01-4.36 0%27/%3E%3C/svg%3E\';\\n  if(ico){ico.href=svg;ico.type=\'image/svg+xml\';}\\n  else{ico=document.createElement(\'link\');ico.rel=\'icon\';ico.type=\'image/svg+xml\';ico.href=svg;document.head.appendChild(ico);}\\n})();\\n</script>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Site Footer: Links + Contact + Legal"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
